const html = $json.body || $json.data || $json.html || '';

function decodeHtml(str) {
  return str
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>');
}

function stripTags(str) {
  return typeof str === 'string' ? str.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim() : str;
}

function tryParseJson(text) {
  try {
    return JSON.parse(text);
  } catch {
    return null;
  }
}

const scriptRegex = /<script[^>]*type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi;
let match;
let ldJsonObjects = [];

while ((match = scriptRegex.exec(html)) !== null) {
  const raw = decodeHtml(match[1].trim());
  const parsed = tryParseJson(raw);
  if (parsed) {
    if (Array.isArray(parsed)) {
      ldJsonObjects.push(...parsed);
    } else {
      ldJsonObjects.push(parsed);
    }
  }
}

let eventObj = ldJsonObjects.find(obj => obj['@type'] === 'Event');

if (!eventObj) {
  for (const obj of ldJsonObjects) {
    if (obj['@graph'] && Array.isArray(obj['@graph'])) {
      const found = obj['@graph'].find(x => x['@type'] === 'Event');
      if (found) {
        eventObj = found;
        break;
      }
    }
  }
}

if (!eventObj) {
  throw new Error('No Event JSON-LD found on the page. The page structure may have changed or the event may block scraping.');
}

const offers = Array.isArray(eventObj.offers) ? eventObj.offers : eventObj.offers ? [eventObj.offers] : [];
const firstOffer = offers[0] || {};
const location = eventObj.location || {};
const address = location.address || {};
const organizer = eventObj.organizer || {};

return [{
  json: {
    eventUrl: $input.first().json.eventUrl,
    title: eventObj.name || null,
    description: stripTags(eventObj.description || null),
    startDate: eventObj.startDate || null,
    endDate: eventObj.endDate || null,
    eventStatus: eventObj.eventStatus || null,
    image: Array.isArray(eventObj.image) ? eventObj.image[0] : eventObj.image || null,
    organizerName: organizer.name || null,
    venueName: location.name || null,
    streetAddress: address.streetAddress || null,
    addressLocality: address.addressLocality || null,
    addressRegion: address.addressRegion || null,
    postalCode: address.postalCode || null,
    addressCountry: address.addressCountry || null,
    price: firstOffer.price || null,
    priceCurrency: firstOffer.priceCurrency || null,
    availability: firstOffer.availability || null,
    ticketUrl: firstOffer.url || eventObj.url || $input.first().json.eventUrl
  }
}];
